using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_f172e90dc06e42bd8c2be93eea3a6ae5.Client;

/// <summary>
/// Reads the persisted user info on the WebAssembly client and reconstructs the authentication state.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authenticationStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState state)
    {
        if (!state.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) || userInfo is null)
        {
            _authenticationStateTask = _unauthenticated;
            return;
        }

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Email),
            new(ClaimTypes.Email, userInfo.Email),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        _authenticationStateTask = Task.FromResult(
            new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(claims, "Persistent"))));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authenticationStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_f172e90dc06e42bd8c2be93eea3a6ae5.Client;

namespace sv_f172e90dc06e42bd8c2be93eea3a6ae5;

/// <summary>
/// Server-side AuthenticationStateProvider that hardcodes a logged-in user
/// and persists the identity to PersistentComponentState so the WebAssembly
/// client can pick it up after the runtime switch.
/// </summary>
public sealed class PersistingAuthenticationStateProvider : AuthenticationStateProvider, IHostEnvironmentAuthenticationStateProvider, IDisposable
{
    private static readonly string[] Roles = ["User", "Editor"];

    private readonly PersistentComponentState _state;
    private readonly PersistingComponentStateSubscription _subscription;

    private Task<AuthenticationState>? _authenticationStateTask;

    public PersistingAuthenticationStateProvider(PersistentComponentState persistentComponentState)
    {
        _state = persistentComponentState;
        _subscription = _state.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);

        // Build the hardcoded identity for bob@example.com.
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, "bob@example.com"),
            new(ClaimTypes.Email, "bob@example.com"),
        };

        foreach (var role in Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        var principal = new ClaimsPrincipal(new ClaimsIdentity(claims, "Hardcoded"));
        _authenticationStateTask = Task.FromResult(new AuthenticationState(principal));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() =>
        _authenticationStateTask ?? throw new InvalidOperationException("Authentication state not set.");

    public void SetAuthenticationState(Task<AuthenticationState> authenticationStateTask)
    {
        _authenticationStateTask = authenticationStateTask;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await GetAuthenticationStateAsync();
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated != true)
            return;

        var email = principal.FindFirst(ClaimTypes.Email)?.Value ?? "";
        var roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

        _state.PersistAsJson(nameof(UserInfo), new UserInfo
        {
            Email = email,
            Roles = roles,
        });
    }

    public void Dispose() => _subscription.Dispose();
}

